#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1005,mod=998244353;
ll c,f,ansc,ansf;
int n,m,t,id,dp[N][N],t1,t2;
string s[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t>>id;
	while(t--)
	{
		cin>>n>>m>>c>>f;
		ansc=ansf=0;
		for(int i=1;i<=n;i++)
		{
			cin>>s[i];
			s[i]=" "+s[i];
		}
		memset(dp,0,sizeof(dp));
		for(int i=1;i<=n;i++)
		{
			for(int j=m-1;j>0;j--)
			{
				if(s[i][j]=='1') dp[i][j]=-1;
				else if(s[i][j+1]=='0') dp[i][j]=dp[i][j+1]+1;
			}
		}
		for(int i=1;i<m;i++)
		{
			t1=t2=0;
			for(int j=1;j<=n;j++)
			{
				if(dp[j][i]==-1)
				{
					t1=t2=0;
					continue;
				}
				ansc=(ansc+((ll)dp[j][i]*(t1%mod)))%mod;
				ansf=(ansf+t2%mod)%mod;
				t2=(t2+((ll)dp[j][i]*t1)%mod)%mod;
				t1=(t1+max(0,dp[j-1][i]))%mod;
			}
		}
		cout<<(c*ansc)%mod<<" "<<(f*ansf)%mod<<'\n';
	}
	return 0;
}
